// TridgeDetergent state diagram states
typedef enum
{
    FSM_STATE_NONE,
    FSM_STATE_INITIALIZE, // PlantUML diagram state INITIALIZE
    FSM_STATE_PUMP_ON, // PlantUML diagram state PUMP_ON
    FSM_STATE_TRIDGE_DISPENSE_COMPLETE // PlantUML diagram state TRIDGE_DISPENSE_COMPLETE
} TRIDGE_DETERGENT_FSM_STATE_TYPE;
// Defines the total number of enumerated values in the TRIDGE_DETERGENT_FSM_STATE_TYPE enumeration.
#define NUM_OF_FSM_STATES 4

// declaration of the structure that will be passed as a function argument to the state machine auto generated functions
typedef struct
{
    TRIDGE_DETERGENT_FSM_STATE_TYPE State; // the current state of the state machine
    BOOL_TYPE Transition; // TRUE event triggered a state transition else FALSE
} TRIDGE_DETERGENT_FSM_VAR_TYPE;

/*
 * TridgeDetergent state diagram events.
 * The lower byte is used for defining state diagram events.
 * The upper byte is used for defining external modules.  External modules used when events from another modules API are defined in the state diagram.
 * Format for defining an external module event in the state diagram: module_name = module_event
 * To dispatch the external module event to the state machine: DISPATCH_FSM_EVENT(mdoule_name + module_event)
 */
typedef enum
{
    // private events
    FSM_EVENT_CARTRIDGE_CHANGED = 1, // PlantUML diagram event CartridgeChanged
    FSM_EVENT_NO_CARTRIDGE_DATA, // PlantUML diagram event NoCartridgeData
    FSM_EVENT_TAG_STATUS_READ, // PlantUML diagram event TagStatusRead
    FSM_EVENT_TIMER_EXPIRED // PlantUML diagram event TimerExpired
} TRIDGE_DETERGENT_FSM_EVENT_TYPE;

// Tridge Detergent State Machine state machine control functions
static void TridgeDetergentFsmInitialize(TRIDGE_DETERGENT_FSM_STATE_TYPE * state);
static void TridgeDetergentFsmExecute(TRIDGE_DETERGENT_FSM_STATE_TYPE * state);
static void TridgeDetergentFsmEvent(TRIDGE_DETERGENT_FSM_EVENT_TYPE event, FSM_CUSTOMIZATION_FUNCTION_ARGUMENT);
static TRIDGE_DETERGENT_FSM_VAR_TYPE TridgeDetergentBuildFsmVar(TRIDGE_DETERGENT_FSM_STATE_TYPE state);

// Tridge Detergent State Machine state machine customization function prototypes
static void CheckCartridge(FSM_CUSTOMIZATION_FUNCTION_ARGUMENT);
static void CheckTagStatusRead(FSM_CUSTOMIZATION_FUNCTION_ARGUMENT);
static void DispenseDetergent(FSM_CUSTOMIZATION_FUNCTION_ARGUMENT);
static void SaveTagSerialNumber(FSM_CUSTOMIZATION_FUNCTION_ARGUMENT);
static void StartDispensingTimer(FSM_CUSTOMIZATION_FUNCTION_ARGUMENT);
static void UpdateDispensingTimer(FSM_CUSTOMIZATION_FUNCTION_ARGUMENT);

//===================================================================================================================
// Function definitions.
//===================================================================================================================
/**
 * @brief Configures the TridgeDetergent state machine to start execution from the Pseudo Initial state.
 * @param state: pointer to the state machine state variable
 */
static void TridgeDetergentFsmInitialize(TRIDGE_DETERGENT_FSM_STATE_TYPE * state)
{
    // [*] --> INITIALIZE
    *state = FSM_STATE_INITIALIZE;
}

/**
 * @brief Executes the TridgeDetergent state machine do actions.
 * @param state: pointer to the state machine state variable
 */
static void TridgeDetergentFsmExecute(TRIDGE_DETERGENT_FSM_STATE_TYPE * state)
{
    TRIDGE_DETERGENT_FSM_VAR_TYPE fsm_var = TridgeDetergentBuildFsmVar(*state);
    switch ( fsm_var.State )
    {
        default:
            // do nothing
            break;
        case FSM_STATE_INITIALIZE:
            // INITIALIZE: do / CheckTagStatusRead
            CheckTagStatusRead(&fsm_var);
            break;
        case FSM_STATE_PUMP_ON:
            // PUMP_ON: do /  CheckCartridge   DispenseDetergent
            CheckCartridge(&fsm_var);
            if ( fsm_var.Transition == FALSE )
            {
                DispenseDetergent(&fsm_var);
            }
            break;
    }
    *state = fsm_var.State;
}

/**
 * NOTE: The DISPATCH_FSM_EVENT(event) macro should be used instead of this function to dispatch events to the
 *       state machine to make maintaining and updating the state machine customization functions easier.
 *
 * @brief Dispatch the event to the TridgeDetergent state machine and consume it.
 * @param event: the event to dispatch to the state machine
 */
static void TridgeDetergentFsmEvent(TRIDGE_DETERGENT_FSM_EVENT_TYPE event, FSM_CUSTOMIZATION_FUNCTION_ARGUMENT)
{
    fsm_var->Transition = FALSE;
    switch ( event )
    {
        default:
            // do nothing
            break;
        case FSM_EVENT_CARTRIDGE_CHANGED: // event CartridgeChanged
            switch ( fsm_var->State )
            {
                default:
                    // do nothing
                    break;
                case FSM_STATE_PUMP_ON:
                    {
                        // PUMP_ON --> PUMP_ON: CartridgeChanged  / UpdateDispensingTimer

                        // transition action
                        UpdateDispensingTimer(fsm_var);
                        // define state being transitioned to
                        fsm_var->State = FSM_STATE_PUMP_ON;
                        fsm_var->Transition = TRUE;
                    }
                    break;
            }
            break;
        case FSM_EVENT_NO_CARTRIDGE_DATA: // event NoCartridgeData
            switch ( fsm_var->State )
            {
                default:
                    // do nothing
                    break;
                case FSM_STATE_INITIALIZE:
                    {
                        // INITIALIZE --> TRIDGE_DISPENSE_COMPLETE: NoCartridgeData

                        // define state being transitioned to
                        fsm_var->State = FSM_STATE_TRIDGE_DISPENSE_COMPLETE;
                        fsm_var->Transition = TRUE;
                    }
                    break;
                case FSM_STATE_PUMP_ON:
                    {
                        // PUMP_ON --> TRIDGE_DISPENSE_COMPLETE: NoCartridgeData

                        // define state being transitioned to
                        fsm_var->State = FSM_STATE_TRIDGE_DISPENSE_COMPLETE;
                        fsm_var->Transition = TRUE;
                    }
                    break;
            }
            break;
        case FSM_EVENT_TAG_STATUS_READ: // event TagStatusRead
            switch ( fsm_var->State )
            {
                default:
                    // do nothing
                    break;
                case FSM_STATE_INITIALIZE:
                    {
                        // INITIALIZE --> PUMP_ON: TagStatusRead / SaveTagSerialNumber         StartDispensingTimer

                        // transition action
                        SaveTagSerialNumber(fsm_var);
                        StartDispensingTimer(fsm_var);
                        // define state being transitioned to
                        fsm_var->State = FSM_STATE_PUMP_ON;
                        fsm_var->Transition = TRUE;
                    }
                    break;
            }
            break;
        case FSM_EVENT_TIMER_EXPIRED: // event TimerExpired
            switch ( fsm_var->State )
            {
                default:
                    // do nothing
                    break;
                case FSM_STATE_PUMP_ON:
                    {
                        // PUMP_ON --> TRIDGE_DISPENSE_COMPLETE: TimerExpired

                        // define state being transitioned to
                        fsm_var->State = FSM_STATE_TRIDGE_DISPENSE_COMPLETE;
                        fsm_var->Transition = TRUE;
                    }
                    break;
            }
            break;
    }
}

/**
 * @brief Define the TRIDGE_DETERGENT_FSM_VAR_TYPE with the passed state argument
 * @param state = the current state of the state machine
 * @return = the TRIDGE_DETERGENT_FSM_VAR_TYPE initialized with the state argument
 */
static TRIDGE_DETERGENT_FSM_VAR_TYPE TridgeDetergentBuildFsmVar(TRIDGE_DETERGENT_FSM_STATE_TYPE state)
{
    TRIDGE_DETERGENT_FSM_VAR_TYPE fsm_var;
    fsm_var.State = state;
    fsm_var.Transition = FALSE;
    return ( fsm_var );
}



#endif /* TRIDGEDETERGENT_FSM_H_ */
